#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
inline void Swap(int &x,int &y){int tmp=x;x=y;y=tmp;}
inline int Max(int x,int y){return x>y?x:y;}inline int Min(int x,int y){return x<y?x:y;}
const int N=1e6+10;
int ans[N<<2],lmx[N<<2],rmn[N<<2],lrs[N<<2],rrs[N<<2],nrs[N<<2],sum[N<<2],a[N],n;
inline void update(int cur)
{
	int l=cur<<1,r=cur<<1|1;sum[cur]=sum[l]+sum[r];
	lmx[cur]=Max(lmx[l],sum[l]+lmx[r]);rmn[cur]=Min(rmn[l]+sum[r],rmn[r]);
	lrs[cur]=Max(Max(lrs[l],lrs[r]-sum[l]),nrs[l]+lmx[r]);
	rrs[cur]=Max(Max(rrs[r],rrs[l]+sum[r]),nrs[r]-rmn[l]);
	nrs[cur]=Max(nrs[l]+sum[r],nrs[r]-sum[l]);
	ans[cur]=Max(Max(Max(ans[l],ans[r]),lrs[r]-rmn[l]),rrs[l]+lmx[r]);
}
inline void build(int l=1,int r=n,int cur=1)
{
	if(l==r)
	{
		sum[cur]=a[l];lmx[cur]=Max(0,sum[cur]);rmn[cur]=Min(0,sum[cur]);
		lrs[cur]=rrs[cur]=ans[cur]=nrs[cur]=1;return;
	}
	int mid=(l+r)>>1;build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);update(cur);
}
inline void add(int pos,int l=1,int r=n,int cur=1)
{
	if(l==r){sum[cur]*=-1;lmx[cur]=Max(sum[cur],0);rmn[cur]=Min(sum[cur],0);return;}
	int mid=(l+r)>>1;if(pos<=mid)add(pos,l,mid,cur<<1);else add(pos,mid+1,r,cur<<1|1);update(cur); 
}
char ch[N];
int main()
{
	read();int Q=read();scanf("%s",ch);
	n=strlen(ch);rep(1,n,i)a[i]=(ch[i-1]=='('?1:-1);
//	rep(1,n,i)printf("%d ",a[i]);puts("");
	build();printf("%d\n",ans[1]);rep(1,Q,i)
	{
		int x=read(),y=read();
		if(a[x]^a[y])add(x),add(y),Swap(a[x],a[y]);
		printf("%d\n",ans[1]);
	}
	return 0;
}
